// Some portions generated by Co-Pilot
import React from "react";
import { render, act, cleanup } from "@testing-library/react";
import { describe, it, expect, vi, afterEach, beforeEach } from "vitest";
import HubspotForm from "../index";

describe("HubspotForm", () => {
  afterEach(() => {
    cleanup();
    delete (window as Window & { hbspt?: unknown }).hbspt;
  });

  it("renders the hubspotForm div", () => {
    const { container } = render(<HubspotForm portalId="123" formId="abc" />);
    expect(container.querySelector("#hubspotForm")).not.toBeNull();
  });

  it("appends a script tag to document body", async () => {
    await act(async () => {
      render(<HubspotForm portalId="123" formId="abc" />);
    });
    const script = document.body.querySelector(
      'script[src="https://js.hsforms.net/forms/v2.js"]',
    );
    expect(script).not.toBeNull();
  });

  it("calls hbspt.forms.create when script loads", async () => {
    const createMock = vi.fn();
    (window as Window & { hbspt?: unknown }).hbspt = {
      forms: { create: createMock },
    };

    let capturedScript: HTMLScriptElement | null = null;
    const originalAppendChild = document.body.appendChild.bind(document.body);
    vi.spyOn(document.body, "appendChild").mockImplementation((node) => {
      const result = originalAppendChild(node);
      if ((node as HTMLElement).tagName === "SCRIPT") {
        capturedScript = node as HTMLScriptElement;
      }
      return result;
    });

    await act(async () => {
      render(<HubspotForm portalId="123" formId="abc" />);
    });

    // Fire the load event on the script
    await act(async () => {
      capturedScript?.dispatchEvent(new Event("load"));
    });

    expect(createMock).toHaveBeenCalledWith(
      expect.objectContaining({
        portalId: "123",
        formId: "abc",
        target: "#hubspotForm",
      }),
    );

    vi.restoreAllMocks();
  });

  it("calls onFormSubmit callback when form is submitted", async () => {
    const createMock = vi.fn();
    const onFormSubmit = vi.fn();
    (window as Window & { hbspt?: unknown }).hbspt = {
      forms: { create: createMock },
    };

    let capturedScript: HTMLScriptElement | null = null;
    const originalAppendChild = document.body.appendChild.bind(document.body);
    vi.spyOn(document.body, "appendChild").mockImplementation((node) => {
      const result = originalAppendChild(node);
      if ((node as HTMLElement).tagName === "SCRIPT") {
        capturedScript = node as HTMLScriptElement;
      }
      return result;
    });

    await act(async () => {
      render(
        <HubspotForm portalId="123" formId="abc" onFormSubmit={onFormSubmit} />,
      );
    });

    await act(async () => {
      capturedScript?.dispatchEvent(new Event("load"));
    });

    // Invoke the onFormSubmit callback registered with hbspt
    const createArgs = createMock.mock.calls[0][0];
    await act(async () => {
      createArgs.onFormSubmit(null);
    });

    expect(onFormSubmit).toHaveBeenCalled();
    vi.restoreAllMocks();
  });

  it("removes script from body on unmount", async () => {
    const { unmount } = render(<HubspotForm portalId="123" formId="abc" />);

    const script = document.body.querySelector(
      'script[src="https://js.hsforms.net/forms/v2.js"]',
    );
    expect(script).not.toBeNull();

    await act(async () => {
      unmount();
    });

    const scriptAfter = document.body.querySelector(
      'script[src="https://js.hsforms.net/forms/v2.js"]',
    );
    expect(scriptAfter).toBeNull();
  });
});
